// TestScore_SupportedLanguage_StillWorks is a regression guard that ensures
// a realistic Go unit with multiple evidence kinds produces a real grade
// and non-zero status. This prevents changes that accidentally break the
// scoring pipeline for supported languages.
func TestScore_SupportedLanguage_StillWorks(t *testing.T) {
	unit := domain.NewUnit(domain.NewUnitID("go", "main.go", "main"), domain.UnitTypeFunction)
	_ = unit // unit identity is used by the scoring context

	ev := []domain.Evidence{
		evidence.CodeMetrics{TotalLines: 100, CodeLines: 80, Complexity: 15}.ToEvidence(),
		evidence.GitStats{CommitCount: 42, AuthorCount: 3, AgeDays: 100}.ToEvidence(),
		evidence.LintResult{Tool: "golangci-lint", ErrorCount: 0}.ToEvidence(),
	}

	scores := engine.Score(ev, policy.EvaluationResult{Passed: true})

	// A real grade should be assigned (not the zero value)
	avg := scores.WeightedAverage(nil)
	if avg <= 0 {
		t.Errorf("weighted average = %f, want > 0 for supported language", avg)
	}

	grade := domain.GradeFromScore(avg)
	if grade == domain.Grade(0) && avg < 0.60 {
		t.Errorf("grade from score %f = %v, want a real grade (not F for clean evidence)", avg, grade)
	}

	// Status should not be zero value for a real score
	status := engine.StatusFromScore(avg, false)
	if status == domain.Status(0) && avg < 0.80 {
		t.Errorf("status from score %f = %v, want non-zero status", avg, status)
	}
}

// TestScore_DefaultsNotInjected guards against the former 0.5 default injection
// bug where dimensions without evidence were assigned 0.5. After the fix,
// dimensions without evidence should simply be absent from the map.
func TestScore_DefaultsNotInjected(t *testing.T) {
	// A unit with only structural evidence (no code metrics, no lint, no tests)
	// This simulates a generic-like unit where only structural analysis ran.
	ev := []domain.Evidence{
		{
			Kind:   domain.EvidenceKindStructural,
			Source: "structural",
			Passed: true,
			Metrics: map[string]float64{
				"func_lines": 10,
			},
		},
	}

	scores := engine.Score(ev, policy.EvaluationResult{Passed: true})

	// No dimension should have the former default value of 0.5
	for dim, val := range scores {
		if val == 0.5 {
			t.Errorf("dimension %s has value 0.5 (former default injected); want no default injection", dim)
		}
	}

	// Dimensions without evidence should be absent — only readability
	// (from func_lines) should be present in this case
	if len(scores) == 0 {
		t.Error("expected at least readability dimension from func_lines metric")
	}
}

// BUG(iksnae/code-certification#25): scoreFromMetrics incorrectly assigns
// excellent (0.95) maintainability when complexity=0 for unmeasured languages.
//
// TestScore_UnmeasuredComplexity_NotScoredExcellent documents the current
// (buggy) behavior: when a Swift/generic file has no complexity analyzer,
// the complexity metric defaults to 0. The scorer treats complexity=0 as
// "excellent" (≤5 → 0.95), assigning maintainability=0.95 when it should
// instead recognize that complexity was never measured and leave the
// dimension absent.
//
// When the bug is fixed, this test must be updated to assert that
// maintainability is absent (or not 0.95) when complexity=0 for
// unmeasured languages.
func TestScore_UnmeasuredComplexity_NotScoredExcellent(t *testing.T) {
	ev := []domain.Evidence{
		{
			Kind:   domain.EvidenceKindMetrics,
			Source: "generic",
			Passed: true,
			Metrics: map[string]float64{
				"complexity": 0,
				"coverage":   0,
			},
		},
	}

	scores := engine.Score(ev, policy.EvaluationResult{Passed: true})

	// Current buggy behavior: complexity=0 is treated as excellent.
	// This documents the status quo; fix bug #25 to change this assertion.
	v, ok := scores[domain.DimMaintainability]
	if !ok {
		t.Log("maintainability absent for complexity=0 — bug #25 may be fixed!")
		return
	}
	if v != 0.95 {
		t.Logf("maintainability = %f for complexity=0 (not 0.95) — bug #25 may be fixed!", v)
		return
	}
	// Known bug: complexity=0 (unmeasured) yields 0.95 maintainability.
	// When fixed, the above branches will log and this line won't be reached.
	t.Log("BUG(iksnae/code-certification#25): maintainability = 0.95 for complexity=0 (unmeasured). " +
		"Complexity was never measured; scorer should not assign excellent maintainability.")
}

